$(document).ready(function () {
    $('.pop-row').hide();

    let popItem = $('.c-image');
    let popButton = $('.pop-button').parent();

    $(popButton).on('click', function (e) {
      e.preventDefault();
      e.stopPropagation();

      $('.pop-row').hide();

      hRef = $(this).attr('id');
      $('.'+ hRef).show();

      console.log('.'+ hRef);
    });

    $(popItem).on('click', function (e) {
      e.preventDefault();
      e.stopPropagation();

      $('.pop-row').hide();

      hRef = $(this).attr('id');
      $('.'+ hRef).show();

      console.log('.'+ hRef);
    });

    // Show exit intent popup
    $(document).on('mouseleave', function (e) {
      if (e.clientY < 50) { // Trigger when the cursor leaves the page (exit intent)
        $('.pop-row').hide(); // Hide all pop-ups
        $('.exit-popup').show(); // Show the exit intent popup
      }
    });
  });

