/* add Guide and order checkbox custom */
.order-bump-container .main-section {
    display: none;
}

.add-option-btn {
    max-width: 160px;
    width: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto;
}

.add-option-btn.option-added {
    background-color: #baf1ca;
    border-color: rgb(0, 153, 0);
    color: rgb(0, 153, 0);
    transition: all 0.3s ease;
}

.add-option-btn.option-added:hover {
    background-color: #e43b2c;
    border-color: #e43b2c;
    color: #ffffff;
}

.add-option-btn .main-heading-group {
    display: flex !important;
    align-items: center;
    justify-content: center;
}

.add-option-btn .button-icon-start {
    order: 2;
}

.add-option-btn.option-added:hover .button-icon-start {
    display: none;
}

.add-option-btn .main-heading-button {
    order: 3;
}

.add-option-btn .button-icon-end {
    order: 1;
    display: none;
    margin-left: 0;
    margin-right: 5px;
}

.add-option-btn.option-added:hover .button-icon-end {
    display: block;
}

.add-option-btn.option-added:hover .main-heading-button {
    font-size: 0;
}

.add-option-btn.option-added .main-heading-button::before {
    content: 'REMOVE';
    font-size: 0;
}

.add-option-btn.option-added:hover .main-heading-button::before {
    font-size: 20px;
}

