// External scripts (add to page head or before closing body tag):
// <script src="https://code.jquery.com/jquery-3.7.0.slim.min.js" integrity="sha256-tG5mcZUtJsZvyKAxYLVXrmjKBVLd6VpVccqz/r4ypFE=" crossorigin="anonymous"></script>

jQuery(document).ready(function() {

  var mouseX = 0, mouseY = 0;
  var xp = 0, yp = 0;

  $(document).mousemove(function(e){
    mouseX = e.pageX - 30;
    mouseY = e.pageY - 30; 
  });

  setInterval(function(){
    xp += ((mouseX - xp)/6);
    yp += ((mouseY - yp)/6);
    $("#circle").css({left: xp +'px', top: yp +'px'});
  }, 20);

});

css:
Once you are done grabbing the custom icon from design, upload it on GHL then do the following: 

**1.** First, add the bullet list element and choose any random icon from the choices.

**2.** And then, add a custom class on the bullet list element, for this sample I did use: 
**redcross-list

3**. Lastly, add this on your CSS code, make sure to put comment label so that it's easy to navigate:

.c-bullet-list .redcross-list ul{
    padding: 0 !important;
}
.c-bullet-list .redcross-list ul li::marker { /* this is to hide the default icon*/
    color: transparent !important;
    font-size: 8px !important;
}
.c-bullet-list .redcross-list ul li {
    position: relative;
    padding-left: 40px !important;
    padding-top: 10px;
    padding-bottom: 10px;
}
.c-bullet-list .redcross-list ul li::before {
    content: "";
    position: absolute;
    left: 0 !important;
    width: 24px; /* change this value whatever the width of your custom icon has */
    height: 25px; /* change this value whatever the height of your custom icon has */
    margin: 0 !important;
    top: 13px;
    background-image: url('https://storage.googleapis.com/msgsndr/Ng3W3Gk7jDA6Yhj8i16z/media/64e765fccee95e7259a2d7c7.png');
    background-size: contain;
    background-repeat: no-repeat;
}

