/* button animation */
:root {
    --shine-degree: 120deg;
    --shine-color: rgba(255, 255, 255, 0.4);
    --shine-effect: linear-gradient(var(--shine-degree),
            transparent,
            var(--shine-color),
            transparent);
}

@keyframes button-shine {
    0% {
        left: -200%;
    }

    100% {
        left: 200%;
    }
}

.shining-btn{
	position: relative;
}

.shining-btn::before {
    content: "";
    position: absolute;
    top: 0;
    width: 100%;
    height: 100%;
    background: var(--shine-effect);
    left: -200%;
    transition: all 0.65s ease-in-out;
    animation: button-shine 3s alternate infinite ease-in-out;
    filter: blur(1.5rem);
}

