.marquee-logos {
        position: relative;
        overflow: hidden;
        display: flex;
    }
    .hero__logos-wrapper {
        animation: marquee--move__logos 35s linear infinite;
        display: flex;
        white-space: nowrap;
        will-change: transform;
        width: 1300px;
        gap: 15px;
        align-items: center;
    }
    .marquee-logos .hero-client-logo {
        object-fit: contain;
        display: inline-block;
        width: 8.625rem;
        height: 2.375rem;
    }
    .marquee-logos::before {
        content: '';
        top: 0%;
        bottom: 0%;
        left: 0%;
        right: auto;
        position: absolute;
        width: 2rem;
        background: linear-gradient(to right, rgba(255,255,255,1) 0%,rgba(255,255,255,0) 100%);
        z-index: 1;
    }
    .marquee-logos::after {
        content: '';
        top: 0%;
        bottom: 0%;
        left: auto;
        right: 0%;
        position: absolute;
        width: 2rem;
        background: linear-gradient(to right,  rgba(255,255,255,0) 0%,rgba(255,255,255,1) 100%);
        z-index: 1;
    }

    @keyframes marquee--move__logos{
        0% {
            transform: translateX(0%);
        }
        100% {
            transform: translateX(-100%);
        }
    }

.timeline-row {
    opacity: 0.3;
    transition: all 0.3s ease;
}

.timeline-row .sticky-top > .inner {
    height: auto;
    position: sticky;
    top: 48%;
}

.timeline-title {
    max-width: max-content;
    padding-left: 28% !important;
}

.timeline-title s {
    position: absolute;
    left: 10%;
    transform: scale(4);
    text-decoration: none;
    background-image: linear-gradient(#134181 61%, #009dff);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

.timeline_progress {
