$(".section-timeline").prepend('<div class="timeline_progress"><div class="timeline_progress-bar"></div></div>');

    //check if the element is in viewport
    $.fn.isInViewport = function () {
        var elementTop = $(this).offset().top;

        var elementBottom = elementTop + $(this).outerHeight() / 2;

        var viewportTop = $(window).scrollTop();

        var viewportHalf = viewportTop + $(window).height() / 2;

        return elementBottom > viewportTop && elementTop < viewportHalf;
    };

    //increase target element opacity execution
    // the ".timeline-row" is the class of the element where we are applying the opacity effect
    $(window).on('load resize scroll', function () {
        $('.timeline-row').each(function () {

            if ($(this).isInViewport()) {
                $(this).css('opacity', 1)
            } else {
                $(this).css('opacity', 0.25);
            }

        });
    });

