/* SURVEY FORM */
#surveyForm {
  margin: 0 auto !important;
  padding: 20px;
  width: 100%;
  overflow: hidden;
}

#surveyForm .row {
  display: flex;
  gap: 10px;
}

/* Style the input fields */

#surveyForm input {
    padding: 10px;
    width: 100%;
    font-size: 17px;
    border: 1px solid #aaaaaa;
}

/* Mark input boxes that gets an error on validation: */

#surveyForm input.invalid {
    background-color: #ffdddd;
}

/* Hide all steps by default: */

#surveyForm .tab {
    display: none;
    text-align:center;
}

/* Make circles that indicate the steps of the form: */

.step {
    height: 24px;
    width: 24px;
    margin: 0 5px;
    background-color: #ddd;
    border: none;
    border-radius: 50%;
    display: inline-block;
    opacity: 0.4;
