/*
   * Requires jQuery to be loaded on the page
   */

    var currentTab = 0; // Current tab is set to be the first tab (0)
    var lastAnswerId = "";

    showTab(currentTab); // Display the current tab

    function showTab(n) {

        console.log("Showing tab " + n);
        var tabs = $(".tab");
        $(tabs[n]).show().css('display', 'inline-block');

        if (n == 0) {
            $("#prevBtn").hide();
        } else {
            $("#prevBtn").show().css('display', 'inline-block');
            $($("#surveyForm .step")[n - 1]).addClass("finish");
        }

        if (n > 0 && $(tabs[n]).data("futurePace") == true) {
            $("#prevBtn").hide();

            // Sort out the headers
            var headers = $(".nudge-hl");
            $(headers).hide();

            var nudgeH2 = $(tabs[n]).find(".nudge-hl[data-forid='" + lastAnswerId + "']");
            $(nudgeH2).show();

            // Sort out the images
            var imgs = $(".nudge-img");
            $(imgs).hide();

            var nudgeImg = $(tabs[n]).find(".nudge-img[data-forid='" + lastAnswerId + "']");
            $(nudgeImg).show();
        }

        if ($(tabs[n]).hasClass("last-tab")) {

            if ($(tabs[n]).data("testLb3") == true) {
                $("#survey-h5").html(
                    "Great! We Think You'll LOVE this <span class='highlight-orange'>100% Free Workshop!</span>"
                );
            }

            if ($(tabs[n]).data("ctaButton") == true) {
                $("#nextBtn").html("Save Free Seat For Training");
                $("#prevBtn").hide();
            }

            $("#nextBtn").click(function () {
                //$("#modalPopup").modal('hide');
              $(".closeLPModal").click();
              $('html, body').animate({
                scrollTop: $("#row--24494").offset().top - 100
              }, 700);
            });
        }

        fixStepIndicator(n)
    }

    function nextPrev(n) {

        var tabs = $(".tab");
        var currTab = $(".tab")[currentTab];

        if ($(currTab).data("checkEmpty") == true) {
            if (!checkEmpty()) return false;
        } else {
            $("#empty-error").hide();
        }

        var input = $(currTab).find("input:checked");
        if (!!$(input).attr("id")) {
            lastAnswerId = $(input).attr("id");
        }

        $(currTab).hide();
        currentTab = currentTab + n;
        showTab(currentTab);
    }

    function checkEmpty() {

        var valid = true;
        var tabs = $(".tab");
        var currTab = $(".tab")[currentTab];
        var errorDivId = $(currTab).data("errorDivId");

        var input = $(currTab).find("input:checked");
        if (!$(input).attr("id")) {
            $("#empty-error").show().css('display', 'block');
            valid = false;
        }

        else {
            $("#empty-error").hide();
        }

        return valid;
    }

    function fixStepIndicator(n) {
        console.log("Fixing step " + n);
        var steps = $("#surveyForm .step");
        steps.removeClass("active");
        $(steps[n]).addClass("active");
    }

