//tabs menu
  const menus = document.querySelectorAll('div.tab-menu');
  const sections = document.querySelectorAll('div.tab-content');

  // Add data-option attribute to each section
  sections.forEach((section, index) => {
    section.setAttribute('data-option', `option${index + 1}`);
  });

  // Add data-section attribute to each menu
  menus.forEach((menu, index) => {
    menu.setAttribute('data-section', `option${index + 1}`);
  });

  // Append .tab-corners to each menu
  menus.forEach(menu => {
    const tabCorners = document.createElement('div');
    tabCorners.classList.add('tab-corners');

    const leftCorner = document.createElement('div');
    leftCorner.classList.add('tab-corner', 'is-left');

    const rightCorner = document.createElement('div');
    rightCorner.classList.add('tab-corner', 'is-right');

    tabCorners.appendChild(leftCorner);
    tabCorners.appendChild(rightCorner);

    menu.appendChild(tabCorners);
  });

  // Create a copy of each tab-content and append it to each tab-menu
  sections.forEach((section, index) => {
    const mobileContent = section.cloneNode(true);
    mobileContent.classList.remove('tab-content');
    mobileContent.removeAttribute('data-option');
    mobileContent.classList.add('tab-content-mobile');
    menus[index].appendChild(mobileContent);
  });

  menus.forEach(menu => menu.addEventListener('click', function () {
    // Remove 'active' class from all menus
    menus.forEach(m => m.classList.remove('active'));
    // Add 'active' class to the clicked menu
    menu.classList.add('active');
    // Hide all sections first
    sections.forEach(section => {
      section.classList.add('hidden');
    });
    // Show the section associated with the clicked menu
    // Derive section class based on menu's data-section attribute
    const optionClass = menu.getAttribute('data-section');
    document.querySelector(`[data-option="${optionClass}"]`).classList.remove('hidden');
  }));

  // Simulate a click on the first menu
  if (menus.length > 0) {
    menus[0].click();
  }

